def _sanitize_mission_id(mission_id: str) -> str:
    args = [mission_id]# type: ignore
    kwargs = {}# type: ignore
    return _mutmut_trampoline(x__sanitize_mission_id__mutmut_orig, x__sanitize_mission_id__mutmut_mutants, args, kwargs, None)


